INSERT INTO brands (id, name, slug, logo_url, hero_video_url, description, description_bn, is_active, sort_order, created_at) VALUES ('09db5170-3644-5fff-ba36-6519ed3303c0', 'Toyota', 'toyota', 'https://res.cloudinary.com/demo/image/upload/v1699000000/brands/toyota-logo.png', 'https://customer-abc123.cloudflarestream.com/toyota-hero/manifest/video.m3u8', 'Toyota — reliability, innovation, and the widest service network in Bangladesh.', 'টয়োটা — নির্ভরযোগ্যতা, উদ্ভাবন এবং বাংলাদেশে সবচেয়ে বড় সার্ভিস নেটওয়ার্ক।', TRUE, 0, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('1420c67b-b3c1-52c5-950e-3b20cd41cf6c', '09db5170-3644-5fff-ba36-6519ed3303c0', 'Corolla Cross', 'corolla-cross', 2021, 2025, 'SUV', 'https://images.unsplash.com/photo-1621007947382-bb3c3994e3fb?w=3840&h=2160&fit=crop&q=90&auto=format', 'https://customer-abc123.cloudflarestream.com/toyota-corolla-cross/manifest/video.m3u8', 'https://res.cloudinary.com/demo/raw/upload/v1699000000/models/toyota-corolla-cross.glb', 4850000, 'The Toyota Corolla Cross combines the reliability of the world''s best-selling sedan with versatile SUV proportions. Built on the TNGA-C platform, it offers a elevated driving position, 440 litres of boot space, and Toyota Safety Sense including pre-collision system and lane departure alert. Available with 1.8L petrol or hybrid powertrain, CVT transmission, and all-wheel drive on selected trims. Ideal for Bangladesh families needing ground clearance for monsoon flooding without sacrificing fuel economy. 5-star ASEAN NCAP safety rating.', 'টয়োটা করোলা ক্রস বিশ্বের সর্বাধিক বিক্রিত সেডানের নির্ভরযোগ্যতা SUV-র সুবিধা নিয়ে আসে। ৪৪০ লিটার বুট স্পেস, টয়োটা সেফটি সেন্স ও হাইব্রিড অপশন।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
