INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('c2b08283-d6fc-54b8-b7d1-c006ac4cb39e', '09db5170-3644-5fff-ba36-6519ed3303c0', 'Allion', 'allion', 2018, 2024, 'SEDAN', 'https://images.pexels.com/photos/210019/pexels-photo-210019.jpeg?auto=compress&cs=tinysrgb&w=1920&h=1080&fit=crop&q=85', 'https://customer-abc123.cloudflarestream.com/toyota-allion/manifest/video.m3u8', 'https://res.cloudinary.com/demo/raw/upload/v1699000000/models/toyota-allion.glb', 3200000, 'The Toyota Allion is a premium mid-size sedan favoured by executives and families across Bangladesh. Spacious rear legroom, refined 1.8L engine with CVT, and a plush ride quality make it ideal for Dhaka commuting and highway travel to Chittagong. Features include push-button start, dual-zone climate control, and a comprehensive 6-airbag safety package. Excellent resale value and Toyota''s nationwide service network ensure low total cost of ownership.', 'টয়োটা অ্যালিয়ন প্রিমিয়াম মিড-সাইজ সেডান — প্রশস্ত রিয়ার লেগরুম, ১.৮L CVT ইঞ্জিন ও ৬ এয়ারব্যাগ।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
