INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('5fe58ceb-6d63-56ba-80cf-91b406e17ac3', '09db5170-3644-5fff-ba36-6519ed3303c0', 'Premio', 'premio', 2017, 2023, 'SEDAN', 'https://images.pexels.com/photos/116675/pexels-photo-116675.jpeg?auto=compress&cs=tinysrgb&w=1920&h=1080&fit=crop&q=85', 'https://customer-abc123.cloudflarestream.com/toyota-premio/manifest/video.m3u8', NULL, 2950000, 'The Toyota Premio delivers understated luxury in a practical sedan package. Known for exceptional build quality and whisper-quiet cabin, it features a 1.5L or 1.8L engine paired with smooth CVT transmission. Wood-grain interior trim, powered front seats, and rear armrest with cupholders elevate the passenger experience. A popular reconditioned import choice in Bangladesh with proven durability on local fuel and road conditions.', 'টয়োটা প্রেমিও — শান্ত কেবিন, উন্নত ইন্টেরিয়র ট্রিম ও নির্ভরযোগ্য ১.৫/১.৮L ইঞ্জিন।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
