INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('4fa6bca9-9209-5f05-8680-f9fc00c9d327', '09db5170-3644-5fff-ba36-6519ed3303c0', 'Fortuner', 'fortuner', 2020, 2025, 'SUV', 'https://images.unsplash.com/photo-1519641471654-2ce0a35f7a37?w=3840&h=2160&fit=crop&q=90&auto=format', 'https://customer-abc123.cloudflarestream.com/toyota-fortuner/manifest/video.m3u8', 'https://res.cloudinary.com/demo/raw/upload/v1699000000/models/toyota-fortuner.glb', 7200000, 'The Toyota Fortuner is Bangladesh''s benchmark full-size SUV for families and adventure seekers. Body-on-frame construction, 2.7L petrol or 2.8L diesel engine, and part-time 4WD tackle both city roads and off-road trails. Three-row seating accommodates seven passengers; 200 mm ground clearance handles flooded streets. Towing capacity up to 2,800 kg. Premium G and V trim levels add leather upholstery, JBL audio, and 360° camera.', 'টয়োটা ফরচুনার — ৭ আসন, ৪WD, বডি-অন-ফ্রেম নির্মাণ। পরিবার ও অ্যাডভেঞ্চারের জন্য আদর্শ।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
