INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('8472713e-0055-54cc-8e75-778fd7756bc7', '09db5170-3644-5fff-ba36-6519ed3303c0', 'Rush', 'rush', 2019, 2024, 'SUV', 'https://images.pexels.com/photos/909907/pexels-photo-909907.jpeg?auto=compress&cs=tinysrgb&w=1920&h=1080&fit=crop&q=85', 'https://customer-abc123.cloudflarestream.com/toyota-rush/manifest/video.m3u8', NULL, 3650000, 'The Toyota Rush is a compact 7-seater SUV based on the Daihatsu Terios platform. Its 1.5L engine delivers frugal fuel consumption (12–14 km/L in city driving) while providing 220 mm ground clearance — essential for Bangladesh road conditions. Fold-flat third row expands cargo space for family trips. Compact dimensions ease parking in dense urban areas. Affordable price point with Toyota warranty and service backing.', 'টয়োটা রাশ — কমপ্যাক্ট ৭-সিটার SUV, সাশ্রয়ী জ্বালানি ও ২২০mm গ্রাউন্ড ক্লিয়ারেন্স।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
