INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('4a68bc1c-5f72-5f99-9bc6-63487acac12c', '09db5170-3644-5fff-ba36-6519ed3303c0', 'Axio', 'axio', 2016, 2022, 'SEDAN', 'https://images.pexels.com/photos/170811/pexels-photo-170811.jpeg?auto=compress&cs=tinysrgb&w=1920&h=1080&fit=crop&q=85', 'https://customer-abc123.cloudflarestream.com/toyota-axio/manifest/video.m3u8', NULL, 2100000, 'The Toyota Axio (Corolla Axio) is one of Bangladesh''s most popular reconditioned imports — valued for reliability, low maintenance costs, and excellent fuel economy. The 1.5L 1NZ-FE engine is renowned for lasting 300,000+ km with basic care. Compact sedan dimensions suit city driving; spacious enough for a family of four. Available in X and G grades with varying feature levels. Parts availability and mechanic familiarity are unmatched.', 'টয়োটা অ্যাক্সিও — বাংলাদেশের জনপ্রিয় রিকন্ডিশন্ড সেডান, অত্যন্ত নির্ভরযোগ্য ও সাশ্রয়ী।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
