INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('82a162ab-2772-5fba-9153-bdd3251844ef', 'be365a41-33bb-58b3-b896-f4481be68be0', 'Tucson', 'tucson', 2022, 2025, 'SUV', 'https://images.unsplash.com/photo-1606664515524-ed2f786a0bd6?w=3840&h=2160&fit=crop&q=90&auto=format', 'https://customer-abc123.cloudflarestream.com/hyundai-tucson/manifest/video.m3u8', 'https://res.cloudinary.com/demo/raw/upload/v1699000000/models/hyundai-tucson.glb', 5500000, 'The Hyundai Tucson brings bold Parametric Jewel grille design and a feature-rich cabin to the mid-size SUV segment. 1.6L turbo petrol or 2.0L diesel engines paired with 6-speed automatic or 7DCT transmission. Hyundai SmartSense suite includes blind-spot collision warning and smart cruise control. Dual 10.25" displays, ventilated front seats, and Bose premium audio on top trims. 5-year unlimited km warranty — industry-leading in Bangladesh.', 'হুন্দাই টাকসন — বোল্ড ডিজাইন, স্মার্টসেন্স সেফটি, ৫ বছর ওয়ারেন্টি।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
