INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('a1432d21-3bc7-5271-8e37-7b622b5dd03c', 'be365a41-33bb-58b3-b896-f4481be68be0', 'Creta', 'creta', 2021, 2025, 'SUV', 'https://images.unsplash.com/photo-1617813489046-4c63c5d0c5f4?w=3840&h=2160&fit=crop&q=90&auto=format', 'https://customer-abc123.cloudflarestream.com/hyundai-creta/manifest/video.m3u8', 'https://res.cloudinary.com/demo/raw/upload/v1699000000/models/hyundai-creta.glb', 4200000, 'The Hyundai Creta dominates the compact SUV segment with its coupe-inspired styling and premium interior. 1.5L petrol with CVT or 1.4L turbo with DCT offers choice between efficiency and performance. Panoramic sunroof, 10.25" touchscreen with wireless Android Auto, and ambient lighting create an upscale experience. 430 litres boot space and 190 mm ground clearance suit Bangladesh lifestyle. Bestseller with strong resale demand.', 'হুন্দাই ক্রেটা — কমপ্যাক্ট SUV সেগমেন্টের বেস্টসেলার, প্যানোরামিক সানরুফ ও প্রিমিয়াম ইন্টেরিয়র।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
