INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('e26d38f0-e3e2-5c3a-a266-ec20e2f321e1', 'be365a41-33bb-58b3-b896-f4481be68be0', 'Elantra', 'elantra', 2020, 2024, 'SEDAN', 'https://images.unsplash.com/photo-1555215695-3004980ad54e?w=3840&h=2160&fit=crop&q=90&auto=format', 'https://customer-abc123.cloudflarestream.com/hyundai-elantra/manifest/video.m3u8', NULL, 3800000, 'The Hyundai Elantra combines sporty sedan styling with advanced technology. The 2.0L MPI engine produces 159 hp with smooth 6-speed automatic transmission. Digital cockpit with twin displays, Hyundai SmartSense, and wireless phone charging on premium trims. Low drag coefficient (0.28 Cd) aids fuel efficiency on highway runs between Dhaka and Sylhet. Comfortable ride with independent rear multi-link suspension.', 'হুন্দাই এলান্ত্রা — স্পোর্টি সেডান ডিজাইন, ২.০L ইঞ্জিন ও স্মার্টসেন্স প্রযুক্তি।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
