INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('9b77450b-1bf9-5ad0-b01d-b3fe83a6e980', 'be365a41-33bb-58b3-b896-f4481be68be0', 'Sonata', 'sonata', 2019, 2023, 'SEDAN', 'https://images.unsplash.com/photo-1583121274602-3bbbfa4c903a?w=3840&h=2160&fit=crop&q=90&auto=format', 'https://customer-abc123.cloudflarestream.com/hyundai-sonata/manifest/video.m3u8', NULL, 4500000, 'The Hyundai Sonata is a flagship D-segment sedan offering executive-level comfort and technology. 2.5L GDI engine with 8-speed automatic delivers refined power for highway cruising. Nappa leather seats with massage function, 12-speaker Bose system, and remote smart parking assist on Calligraphy trim. Extended wheelbase provides limousine-like rear space. Ideal for corporate fleet and discerning buyers seeking premium without European price tags.', 'হুন্দাই সোনাটা — ফ্ল্যাগশিপ সেডান, ম্যাসাজ সিট ও রিমোট পার্কিং সহ প্রিমিয়াম ফিচার।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
