INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('369d4d74-3924-53ea-a618-1b37b8f2bcd4', 'be365a41-33bb-58b3-b896-f4481be68be0', 'i10', 'i10', 2018, 2023, 'HATCHBACK', 'https://images.pexels.com/photos/2449454/pexels-photo-2449454.jpeg?auto=compress&cs=tinysrgb&w=1920&h=1080&fit=crop&q=85', 'https://customer-abc123.cloudflarestream.com/hyundai-i10/manifest/video.m3u8', NULL, 1650000, 'The Hyundai i10 is the perfect city car for first-time buyers and urban commuters. Compact 3.6-metre length eases parking in Gulshan and Old Dhaka alike. 1.2L Kappa engine returns 14–16 km/L; responsive handling makes traffic navigation effortless. 8" touchscreen, rear camera, and automatic climate control punch above its price class. Lowest maintenance cost in the Hyundai lineup with 5-year warranty.', 'হুন্দাই i10 — শহরের জন্য আদর্শ কমপ্যাক্ট কার, সাশ্রয়ী জ্বালানি ও কম রক্ষণাবেক্ষণ।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
