INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('1fb2515b-ea56-54ea-ad8f-7cdb0f01a4ad', '69f00f5a-f20f-5637-a36d-711159236f0c', 'X-Trail', 'x-trail', 2021, 2025, 'SUV', 'https://images.unsplash.com/photo-1606664515524-ed2f786a0bd6?w=3840&h=2160&fit=crop&q=90&auto=format', 'https://customer-abc123.cloudflarestream.com/nissan-x-trail/manifest/video.m3u8', 'https://res.cloudinary.com/demo/raw/upload/v1699000000/models/nissan-x-trail.glb', 5800000, 'The Nissan X-Trail is a versatile family SUV with available third-row seating and intelligent 4WD. 2.5L petrol engine with Xtronic CVT delivers smooth, efficient performance. ProPILOT driver assistance reduces fatigue on long highway journeys. Zero Gravity front seats reduce fatigue on Dhaka-Chittagong routes. 700 litres maximum cargo space with seats folded. e-POWER hybrid variant available on newer models for exceptional fuel economy.', 'নিসান এক্স-ট্রেইল — বহুমুখী ফ্যামিলি SUV, প্রোপাইলট সহায়তা ও ৭০০L কার্গো স্পেস।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
