INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('276f91ee-e2bb-5ee6-9930-f3e3ab7ea1bb', '69f00f5a-f20f-5637-a36d-711159236f0c', 'Sunny', 'sunny', 2018, 2023, 'SEDAN', 'https://images.pexels.com/photos/170811/pexels-photo-170811.jpeg?auto=compress&cs=tinysrgb&w=1920&h=1080&fit=crop&q=85', 'https://customer-abc123.cloudflarestream.com/nissan-sunny/manifest/video.m3u8', NULL, 2400000, 'The Nissan Sunny is a budget-friendly sedan trusted by ride-share drivers and families across Bangladesh. Simple, durable 1.5L engine with excellent parts availability and low service costs. Spacious cabin for its class with generous boot for airport runs and grocery hauls. Known for surviving high daily mileage (100+ km/day) with minimal issues. Best value proposition in the Nissan lineup for practical buyers.', 'নিসান সানি — বাজেট-বান্ধব সেডান, রাইড-শেয়ার ও পরিবারের জন্য নির্ভরযোগ্য।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
