INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('e0b41d3b-d075-56e7-a469-b6df0c8c21c3', '69f00f5a-f20f-5637-a36d-711159236f0c', 'Navara', 'navara', 2020, 2025, 'PICKUP', 'https://images.pexels.com/photos/6476589/pexels-photo-6476589.jpeg?auto=compress&cs=tinysrgb&w=1920&h=1080&fit=crop&q=85', 'https://customer-abc123.cloudflarestream.com/nissan-navara/manifest/video.m3u8', 'https://res.cloudinary.com/demo/raw/upload/v1699000000/models/nissan-navara.glb', 5200000, 'The Nissan Navara is a premium pickup truck combining workhorse capability with car-like refinement. 2.5L turbo diesel (190 hp, 450 Nm) tows up to 3,500 kg. Multi-link rear suspension — unique in the segment — delivers SUV-comfortable ride unladen. Intelligent Around View Monitor aids tight manoeuvring. Popular for construction, agriculture, and adventure use across Bangladesh. Pro-4X trim adds off-road hardware.', 'নিসান নভারা — প্রিমিয়াম পিকআপ, ৩৫০০ কেজি টোইং ও SUV-সদৃশ আরাম।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
