INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('7fb492a9-1509-502b-8e81-cbc04dc4838c', '69f00f5a-f20f-5637-a36d-711159236f0c', 'Kicks', 'kicks', 2021, 2024, 'SUV', 'https://images.unsplash.com/photo-1533473156550-15d00a14276d?w=3840&h=2160&fit=crop&q=90&auto=format', 'https://customer-abc123.cloudflarestream.com/nissan-kicks/manifest/video.m3u8', NULL, 3900000, 'The Nissan Kicks is a stylish compact crossover with floating roof design and personalisation options. 1.6L petrol engine with smooth CVT; fuel economy around 13 km/L combined. 422 litres boot and 185 mm ground clearance suit urban Bangladesh lifestyle. NissanConnect 8" display with smartphone integration. Safety Shield 360 includes automatic emergency braking and rear cross-traffic alert. Fresh alternative to established Creta and Corolla Cross rivals.', 'নিসান কিক্স — স্টাইলিশ কমপ্যাক্ট ক্রসওভার, সেফটি শিল্ড ৩৬০ ও ৪২২L বুট।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
