INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('bf0ef73c-2702-52fa-b4b3-add1b6b9ab26', '69f00f5a-f20f-5637-a36d-711159236f0c', 'Teana', 'teana', 2017, 2022, 'SEDAN', 'https://images.unsplash.com/photo-1549317661-bd32c8ce0db2?w=3840&h=2160&fit=crop&q=90&auto=format', 'https://customer-abc123.cloudflarestream.com/nissan-teana/manifest/video.m3u8', NULL, 3500000, 'The Nissan Teana is a premium executive sedan offering V6 smoothness and a cocoon-like cabin. 2.5L or 3.5L VQ-series engine paired with CVT for seamless acceleration. BOSE premium audio, powered rear seats, and dual-panel sunroof create a first-class rear experience. Popular reconditioned import for business executives. Whisper-quiet NVH levels and plush suspension tuning prioritise comfort over sportiness.', 'নিসান টিয়ানা — প্রিমিয়াম এক্সিকিউটিভ সেডান, V6 মসৃণতা ও বোস অডিও।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
