INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('c0ed2b73-c9de-5b0f-90bb-e4d3ca2397f8', '69f00f5a-f20f-5637-a36d-711159236f0c', 'Magnite', 'magnite', 2022, 2025, 'SUV', 'https://images.unsplash.com/photo-1618843479313-40f8afb5110d?w=3840&h=2160&fit=crop&q=90&auto=format', 'https://customer-abc123.cloudflarestream.com/nissan-magnite/manifest/video.m3u8', NULL, 2800000, 'The Nissan Magnite is the most affordable Nissan SUV in Bangladesh — bringing turbocharged performance to the entry segment. 1.0L turbo petrol produces 100 hp with 5-speed manual or CVT. 390 litres boot, 205 mm ground clearance, and compact 4-metre length. Tech Pack adds wireless charging, JBL audio, and 360° camera. Ideal first SUV for young professionals. Competitive pricing with Nissan reliability backing.', 'নিসান ম্যাগনাইট — সবচেয়ে সাশ্রয়ী নিসান SUV, ১.০L টার্বো ও ৩৬০° ক্যামেরা।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
