INSERT INTO brands (id, name, slug, logo_url, hero_video_url, description, description_bn, is_active, sort_order, created_at) VALUES ('24d12c94-5048-5f26-b57b-1caae4aff1fb', 'BAW', 'baw', 'https://res.cloudinary.com/demo/image/upload/v1699000000/brands/baw-logo.png', 'https://customer-abc123.cloudflarestream.com/baw-hero/manifest/video.m3u8', 'BAW — affordable electric mobility for Bangladesh. City EVs, sedans, SUVs, and commercial vans with zero emissions.', 'BAW — বাংলাদেশের জন্য সাশ্রয়ী ইলেকট্রিক গাড়ি। শূন্য নির্গমন, কম চলানো খরচ।', TRUE, 3, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('d7a8aa59-c37b-5b19-b34c-b0ad85c094bb', '24d12c94-5048-5f26-b57b-1caae4aff1fb', 'Pony', 'pony', 2023, 2026, 'HATCHBACK', 'https://images.pexels.com/photos/3861969/pexels-photo-3861969.jpeg?auto=compress&cs=tinysrgb&w=1920&h=1080&fit=crop&q=85', 'https://customer-abc123.cloudflarestream.com/baw-pony/manifest/video.m3u8', 'https://res.cloudinary.com/demo/raw/upload/v1699000000/models/baw-pony.glb', 1850000, 'The BAW Pony is a compact city EV designed for Bangladesh urban commuting. Single-motor FWD with up to 200 km real-world range (Standard) or 280 km (Long Range). Fast 30 kW DC charging adds 80% in 45 minutes. Compact 3.5-metre footprint eases parking in Gulshan and Mirpur. Zero fuel cost, minimal maintenance — no oil changes required. Ideal for ride-share fleets and eco-conscious first-time buyers.', 'BAW পনি — কমপ্যাক্ট সিটি ইভি, ২০০–২৮০ km রেঞ্জ, দ্রুত DC চার্জিং।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
