INSERT INTO car_models (id, brand_id, name, slug, year_from, year_to, body_type, hero_image_url, video_url, model_3d_url, base_price, description, description_bn, is_active, created_at) VALUES ('0d3a430a-f26e-50f7-9420-77fc7bb91877', '24d12c94-5048-5f26-b57b-1caae4aff1fb', 'EV6 Cargo', 'ev6-cargo', 2023, 2026, 'VAN', 'https://images.pexels.com/photos/6476589/pexels-photo-6476589.jpeg?auto=compress&cs=tinysrgb&w=1920&h=1080&fit=crop&q=85', 'https://customer-abc123.cloudflarestream.com/baw-ev6-cargo/manifest/video.m3u8', NULL, 2650000, 'The BAW EV6 Cargo is a commercial electric van for last-mile delivery and small business logistics. 1,200 kg payload capacity, sliding side door, and 220 km range optimized for city routes. Ultra-low running cost vs diesel hiace — ideal for e-commerce and pharmacy delivery fleets. AC fast charge compatible; eligible for green fleet incentives. AutoHub BD offers fleet pricing and bulk charging setup consultation.', 'BAW EV6 কার্গো — ইলেকট্রিক কমার্শিয়াল ভ্যান, ১২০০ kg পে-লোড, ফ্লিট ডেলিভারির জন্য।', TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (brand_id, slug) DO NOTHING;
