INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('8672c551-f409-5dd8-a241-e08de7873721', 'eb0128af-4c16-5620-a614-32362115c2df', 'Toyota Genuine Air Filter', 'toyota-genuine-air-filter', 'ENG-00101', 1850, 48, 'OEM-spec air filter for Toyota petrol engines. High-flow pleated media traps dust and pollen while maintaining airflow for optimal fuel economy. Direct fit replacement — no modification required. Replace every 15,000 km or as indicated by your service schedule. Genuine-quality construction with reinforced rubber seal for a leak-free fit in Bangladesh heat and humidity.', 'টয়োটা পেট্রোল ইঞ্জিনের জন্য ওইএম-স্পেক এয়ার ফিল্টার। উচ্চ-প্রবাহ প্লেটেড মিডিয়া ধুলো ও পোলেন ধরে রাখে এবং জ্বালানি সাশ্রয় বজায় রাখে।', ARRAY['Toyota']::text[], ARRAY['Corolla Cross', 'Allion', 'Premio', 'Axio']::text[], 2016, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
