INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('fd83c2e6-55c3-5e0b-9bed-ef1400828b61', 'eb0128af-4c16-5620-a614-32362115c2df', 'Hyundai Oil Filter Element', 'hyundai-oil-filter-element', 'ENG-00102', 950, 72, 'Spin-on oil filter element engineered for Hyundai Gamma and Nu engine families. Anti-drainback valve prevents dry starts; high-capacity filter media extends oil life between changes. Torque spec: 2/3 turn after gasket contact. Recommended change interval: 5,000 km with mineral oil, 10,000 km with full synthetic in tropical conditions.', 'হুন্দাই গামা ও নু ইঞ্জিন পরিবারের জন্য স্পিন-অন অয়েল ফিল্টার। অ্যান্টি-ড্রেনব্যাক ভালভ শুষ্ক স্টার্ট প্রতিরোধ করে।', ARRAY['Hyundai']::text[], ARRAY['Tucson', 'Creta', 'Elantra', 'i10']::text[], 2018, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
