INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('d459d6fb-4850-5efa-bb9e-581cb9307bd3', 'eb0128af-4c16-5620-a614-32362115c2df', 'Nissan Spark Plug Set (Iridium 4pc)', 'nissan-spark-plug-set-iridium', 'ENG-00103', 4200, 35, 'Set of four iridium-tipped spark plugs for Nissan 4-cylinder engines. Iridium centre electrode delivers consistent ignition, smoother idle, and up to 100,000 km service life. Pre-gapped for factory specification. Includes dielectric grease sachet. Ideal upgrade from standard nickel plugs for improved cold-start performance during Bangladesh winters.', 'নিসান ৪-সিলিন্ডার ইঞ্জিনের জন্য চারটি ইরিডিয়াম টিপ স্পার্ক প্লাগ সেট। ধারাবাহিক ইগনিশন ও মসৃণ আইডল প্রদান করে।', ARRAY['Nissan']::text[], ARRAY['X-Trail', 'Sunny', 'Teana', 'Kicks']::text[], 2017, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
