INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('b74e65df-1b3d-5589-ace6-370d2b37a212', 'eb0128af-4c16-5620-a614-32362115c2df', 'Timing Belt Kit with Water Pump', 'timing-belt-kit-water-pump', 'ENG-00104', 12500, 18, 'Complete timing belt service kit including reinforced belt, tensioner bearing, idler pulley, and water pump assembly. Critical preventive maintenance item — failure can cause catastrophic engine damage. All components meet OEM dimensional tolerances. Professional installation recommended; kit includes alignment marks guide. Service interval: 80,000–100,000 km depending on model.', 'টাইমিং বেল্ট, টেনশনার, আইডলার পুলি ও ওয়াটার পাম্প সহ সম্পূর্ণ কিট। প্রতিরোধমূলক রক্ষণাবেক্ষণের জন্য অত্যাবশ্যক।', ARRAY['Toyota', 'Hyundai']::text[], ARRAY['Allion', 'Premio', 'Elantra', 'Sonata']::text[], 2016, 2023, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
