INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('9048b82b-6a16-5934-a322-f2590fcb3302', 'eb0128af-4c16-5620-a614-32362115c2df', 'Electric Fuel Pump Assembly', 'electric-fuel-pump-assembly', 'ENG-00105', 8900, 14, 'In-tank electric fuel pump module with integrated fuel level sender. Delivers consistent fuel pressure (3.0–3.5 bar) for direct-injection and multi-point systems. Corrosion-resistant fuel lines and OEM-spec electrical connector. Symptoms of failure: hard starting, engine sputtering under load, whining noise from fuel tank. Includes installation gasket.', 'ইন-ট্যাঙ্ক ইলেকট্রিক ফুয়েল পাম্প মডিউল ফুয়েল লেভেল সেন্ডারসহ। ধারাবাহিক ফুয়েল প্রেসার নিশ্চিত করে।', ARRAY['Toyota', 'Nissan']::text[], ARRAY['Corolla Cross', 'Fortuner', 'X-Trail', 'Navara']::text[], 2019, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
