INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('110bb6be-a8eb-5361-baaa-bc5dca6ff2de', 'eb0128af-4c16-5620-a614-32362115c2df', 'Aluminum Radiator Assembly', 'aluminum-radiator-assembly', 'ENG-00106', 14500, 12, 'Full aluminum core radiator with plastic end tanks for superior heat dissipation in stop-and-go Dhaka traffic. Direct OEM replacement — same mounting points and hose connections. Pressure tested to 1.4 bar at factory. Pair with fresh coolant flush for optimal cooling system performance. 12-month warranty against manufacturing defects.', 'ফুল অ্যালুমিনিয়াম কোর রেডিয়েটার ঢাকার ট্রাফিকে উচ্চ তাপ বিকিরণের জন্য। ওইএম রিপ্লেসমেন্ট ফিট।', ARRAY['Toyota', 'Hyundai', 'Nissan']::text[], ARRAY['Corolla Cross', 'Tucson', 'X-Trail', 'Santa Fe']::text[], 2018, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
