INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('ea40a8b0-3cb6-5ef9-8e9d-f2d300fd72b9', 'eb0128af-4c16-5620-a614-32362115c2df', 'Remanufactured Alternator 12V 90A', 'remanufactured-alternator-12v-90a', 'ENG-00107', 11200, 9, 'Remanufactured 12-volt, 90-amp alternator with new voltage regulator, brushes, and bearings. Bench-tested to ISO output standards before dispatch. Restores charging system performance — dim headlights and weak battery are common signs of alternator failure. Includes pulley and mounting hardware. Core exchange discount available at installation.', 'রিম্যানুফ্যাকচার্ড ১২V, ৯০A অল্টারনেটর নতুন ভোল্টেজ রেগুলেটর ও বিয়ারিংসহ।', ARRAY['Toyota', 'Hyundai']::text[], ARRAY['Allion', 'Axio', 'Creta', 'i10']::text[], 2016, 2024, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
