INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('cf35cc97-e275-58e7-af3f-f55a79a3e6ad', 'eb0128af-4c16-5620-a614-32362115c2df', 'PCV Valve & Breather Hose Kit', 'pcv-valve-breather-hose-kit', 'ENG-00108', 1650, 55, 'Positive Crankcase Ventilation valve and reinforced breather hose kit. Prevents oil sludge buildup and maintains proper crankcase pressure. A stuck PCV valve can cause rough idle, oil leaks, and increased oil consumption — common in high-mileage vehicles. Quick DIY replacement; includes hose clamps and installation diagram.', 'পিসিভি ভালভ ও ব্রিদার হোস কিট। তেলের স্লাজজ জমা রোধ করে ও ক্র্যাঙ্ককেস চাপ ঠিক রাখে।', ARRAY['Toyota', 'Hyundai', 'Nissan']::text[], ARRAY['Premio', 'Rush', 'Elantra', 'Sunny']::text[], 2016, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
