INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('e7707527-0fcb-5601-945f-4f446ba621ef', '9d1ed7d0-9b09-5418-9e85-948469aa8c41', 'Front Brake Pad Set — Ceramic', 'front-brake-pad-ceramic', 'BRK-00201', 3200, 40, 'Premium ceramic compound front brake pads for quiet, low-dust braking performance. Chamfered edges reduce squeal; shims included for noise dampening. Excellent heat resistance for repeated stop-start driving. Break-in procedure: 10 gentle stops from 60 km/h. Replace when pad thickness reaches 3 mm. Includes wear indicator clips.', 'প্রিমিয়াম সিরামিক ফ্রন্ট ব্রেক প্যাড — কম ধুলো ও নীরব ব্রেকিং। উচ্চ তাপ সহনশীল।', ARRAY['Toyota', 'Hyundai', 'Nissan']::text[], ARRAY['Corolla Cross', 'Tucson', 'X-Trail']::text[], 2019, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
