INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('5c424fd0-6f30-570e-ba11-174529baec0f', '9d1ed7d0-9b09-5418-9e85-948469aa8c41', 'Vented Brake Disc Rotor (Front Pair)', 'vented-brake-disc-rotor-front', 'BRK-00203', 7800, 22, 'Pair of vented front brake rotors with precision-machined friction surfaces. Vented design improves heat dissipation during heavy braking. Minimum thickness stamped on rotor edge — never machine below spec. Replace rotors when lip exceeds 1.5 mm or surface shows scoring. Coated hub faces resist rust in monsoon conditions.', 'ভেন্টেড ফ্রন্ট ব্রেক রোটর পেয়ার — ভারী ব্রেকিংয়ে তাপ কমায়।', ARRAY['Toyota', 'Nissan']::text[], ARRAY['Fortuner', 'Corolla Cross', 'Navara', 'X-Trail']::text[], 2018, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
