INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('575f416e-2812-5014-9028-bc2dd7f291ee', '9d1ed7d0-9b09-5418-9e85-948469aa8c41', 'Front Brake Caliper (Remanufactured)', 'front-brake-caliper-reman', 'BRK-00204', 9500, 8, 'Remanufactured front brake caliper with new piston seals and guide pin boots. Restores even pad pressure and eliminates sticking caliper symptoms (vehicle pulling, overheated rotor). Pressure-tested and lubricated before shipping. Always replace brake fluid and bleed system after caliper installation. Sold individually — order left or right as needed.', 'রিম্যানুফ্যাকচার্ড ফ্রন্ট ব্রেক ক্যালিপার নতুন সিল ও বুটসহ।', ARRAY['Hyundai', 'Nissan']::text[], ARRAY['Tucson', 'Creta', 'Sunny', 'Kicks']::text[], 2018, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
