INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('62375036-4e3c-59a2-96c3-0bb8da2a82b6', '9d1ed7d0-9b09-5418-9e85-948469aa8c41', 'DOT 4 Brake Fluid 1L', 'dot4-brake-fluid-1l', 'BRK-00205', 650, 120, 'High-performance DOT 4 brake fluid with dry boiling point of 230°C. Absorbs less moisture than DOT 3 for longer service intervals in humid climates. Essential for ABS and stability control systems. Flush every 2 years or 40,000 km. Never mix with DOT 5 silicone fluid. Sealed bottle — use within 12 months of opening.', 'ডিওটি ৪ ব্রেক ফ্লুইড — উচ্চ বয়লিং পয়েন্ট, আর্দ্র আবহাওয়ায় উপযুক্ত।', ARRAY['Toyota', 'Hyundai', 'Nissan']::text[], ARRAY['Corolla Cross', 'Allion', 'Tucson', 'X-Trail', 'Sunny']::text[], 2016, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
