INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('831cd2dc-d728-51f2-a2ff-0219a9d97776', '9d1ed7d0-9b09-5418-9e85-948469aa8c41', 'Rear Handbrake Cable Assembly', 'rear-handbrake-cable-assembly', 'BRK-00206', 2400, 25, 'Complete rear handbrake (parking brake) cable assembly with equalizer. Stainless inner cable resists corrosion from road salt and water. Symptoms of worn cable: excessive handbrake lever travel, vehicle rolling on inclines. Adjust cable tension after installation per workshop manual. Pair with rear drum/shoe inspection if applicable.', 'রিয়ার হ্যান্ডব্রেক কেবল অ্যাসেম্বলি — মরিচা প্রতিরোধী।', ARRAY['Toyota']::text[], ARRAY['Allion', 'Premio', 'Axio', 'Rush']::text[], 2016, 2023, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
