INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('0d202222-6c3f-5e82-acb4-cb694af60461', '9d1ed7d0-9b09-5418-9e85-948469aa8c41', 'Brake Master Cylinder Assembly', 'brake-master-cylinder-assembly', 'BRK-00207', 6800, 11, 'OEM-spec brake master cylinder with integrated reservoir. Converts pedal force to hydraulic pressure for the entire braking system. Internal seal failure causes soft pedal or fluid leak — replace immediately if brake warning light illuminates. Bench-bleed before installation. Includes reservoir cap and mounting gasket.', 'ব্রেক মাস্টার সিলিন্ডার অ্যাসেম্বলি রিজার্ভারসহ — হাইড্রোলিক চাপ তৈরি করে।', ARRAY['Hyundai', 'Nissan']::text[], ARRAY['Elantra', 'Sonata', 'Teana', 'Magnite']::text[], 2017, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
