INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('a8229bb3-8e9a-5c2f-b8de-919ed4bbe55c', '42925fe1-27a1-57e2-b701-8d9abd19760b', 'Front Gas Shock Absorber (Pair)', 'front-gas-shock-absorber-pair', 'SUS-00301', 8500, 20, 'Twin-tube gas-charged front shock absorbers sold as a matched pair. Restores ride comfort and tyre contact on Bangladesh''s mixed road surfaces. Nitrogen gas charge prevents foaming under hard use. Replace shocks in pairs (left + right) for balanced handling. Typical lifespan: 60,000–80,000 km. Includes mounting bushings where applicable.', 'টুইন-টিউব গ্যাস চার্জড ফ্রন্ট শক অ্যাবজরবার পেয়ার। আরামদায়ক রাইড ফিরিয়ে আনে।', ARRAY['Toyota', 'Hyundai']::text[], ARRAY['Corolla Cross', 'Rush', 'Tucson', 'Santa Fe']::text[], 2018, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
