INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('ff2f6020-d373-5283-a6aa-ddbd22e7f825', '42925fe1-27a1-57e2-b701-8d9abd19760b', 'Lower Control Arm Bushing Kit', 'lower-control-arm-bushing-kit', 'SUS-00305', 3400, 28, 'Polyurethane lower control arm bushing kit for improved durability over factory rubber. Reduces deflection under braking and acceleration for sharper steering response. Ideal for high-mileage vehicles with cracked or softened OEM bushings. Press-fit installation requires hydraulic press. Full alignment mandatory after fitment.', 'পলিউরেথেন লোয়ার কন্ট্রোল আর্ম বুশিং কিট — রাবারের চেয়ে টেকসই।', ARRAY['Toyota', 'Nissan']::text[], ARRAY['Axio', 'Rush', 'Navara', 'Kicks']::text[], 2016, 2024, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
