INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('6bc609c1-20ef-5c0e-b634-23a6fb0a6a65', '42925fe1-27a1-57e2-b701-8d9abd19760b', 'Strut Mount & Bearing Kit', 'strut-mount-bearing-kit', 'SUS-00306', 2900, 30, 'Upper strut mount with integrated bearing for smooth steering rotation. Clunking when turning the wheel at standstill indicates worn strut bearing. Rubber isolation pad absorbs road vibration before it reaches the cabin. Replace whenever front shocks are changed. Includes centre nut and dust cap.', 'আপার স্ট্রাট মাউন্ট বিয়ারিংসহ — স্টিয়ারিং ঘূর্ণন মসৃণ করে।', ARRAY['Hyundai', 'Nissan']::text[], ARRAY['Tucson', 'Sonata', 'X-Trail', 'Magnite']::text[], 2018, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
