INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('6f333800-0558-5625-b5a3-31135918a4d8', '42925fe1-27a1-57e2-b701-8d9abd19760b', 'Rear Trailing Arm Bushing', 'rear-trailing-arm-bushing', 'SUS-00307', 2200, 24, 'Rear trailing arm bushing for multi-link rear suspension systems. Worn bushings cause rear-end wandering and uneven rear tyre wear. Hydraulic press required for removal and installation. Inspect companion arm bolts for corrosion — replace if seized. Recommended whenever rear shocks are replaced on vehicles over 80,000 km.', 'রিয়ার ট্রেইলিং আর্ম বুশিং — মাল্টি-লিংক সাসপেনশনের জন্য।', ARRAY['Toyota']::text[], ARRAY['Corolla Cross', 'Allion', 'Fortuner']::text[], 2018, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
