INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('c4f26d04-49bb-571a-86cd-758ac963ba86', 'd467cdb6-9463-5cc9-9660-43b78f94563d', 'Premium Leather Seat Cover Set (5-Seat)', 'premium-leather-seat-cover-5', 'INT-00501', 12500, 20, 'Full-set PU leather seat covers with perforated centre panels for breathability in hot weather. Tailored fit for sedan and compact SUV platforms — includes headrest covers, armrest cover, and ISOFIX cutouts. UV-resistant stitching prevents fading. Installation guide and fitting hooks included. Protects original upholstery and increases resale value.', 'প্রিমিয়াম পিইউ লেদার সিট কভার সেট — গরম আবহাওয়ায় শ্বাস-প্রশ্বাসযোগ্য প্যানেল।', ARRAY['Toyota', 'Hyundai', 'Nissan']::text[], ARRAY['Corolla Cross', 'Allion', 'Elantra', 'Sunny']::text[], 2017, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
