INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('65864bc7-ba41-55b8-99ec-3fed2fec97da', '6271cb65-3f43-52ee-896b-81f15a9a1954', 'Bonnet Guard / Bug Deflector (Smoke)', 'bonnet-guard-bug-deflector', 'EXT-00607', 3200, 22, 'Smoke-tinted acrylic bonnet deflector redirects airflow over the vehicle, reducing stone chips and insect strikes on the windscreen. Chrome stand-off brackets; no-drill tape option included. UV-stabilised material resists yellowing. Popular accessory for pickup trucks on Bangladesh rural highways. Model-specific curvature for clean appearance.', 'বনেট গার্ড / বাগ ডিফ্লেক্টর — পাথর ও পোকামাকড় থেকে উইন্ডশিল্ড রক্ষা।', ARRAY['Nissan']::text[], ARRAY['Navara', 'X-Trail', 'Kicks']::text[], 2019, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
