INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('fa4ab401-2ad0-5b72-97c3-ccc78e5e35f7', '5f060a6d-8b87-5b00-9471-801e7ed7c63d', 'Alloy Wheel 17" (Set of 4)', 'alloy-wheel-17-set-4', 'WHL-00701', 52000, 8, 'Set of four 17×7J alloy wheels with ET45 offset and 5×114.3 PCD — the most common fitment for Japanese and Korean vehicles in Bangladesh. Flow-formed construction balances strength and weight. Gunmetal grey finish. Includes centre caps and lug nuts. Professional balancing and TPMS transfer required at fitment. Load rating: 650 kg per wheel.', '১৭ ইঞ্চি অ্যালয় হুইল সেট (৪টি) — ৫×১১৪.৩ PCD, গানমেটাল গ্রে।', ARRAY['Toyota', 'Hyundai']::text[], ARRAY['Corolla Cross', 'Allion', 'Tucson', 'Creta']::text[], 2018, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
