INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('8cc857f4-e77d-5a3d-bd66-2ef0d490a0e4', '5f060a6d-8b87-5b00-9471-801e7ed7c63d', 'Alloy Wheel 18" (Set of 4)', 'alloy-wheel-18-set-4', 'WHL-00702', 68000, 5, 'Premium 18×8J alloy wheels for SUVs and pickups. Machine-faced spokes with black inner barrel. Rated for off-road and towing duty on Navara and Fortuner platforms. Compatible with factory 265/60R18 and 225/55R18 tyre sizes. Hub-centric rings included for vibration-free ride. Sold as set of four — single wheel not available.', '১৮ ইঞ্চি প্রিমিয়াম অ্যালয় হুইল SUV ও পিকআপের জন্য।', ARRAY['Toyota', 'Nissan']::text[], ARRAY['Fortuner', 'X-Trail', 'Navara', 'Corolla Cross']::text[], 2019, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
