INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('ed2b40ab-5405-5f10-81e1-a1618b96293b', '5f060a6d-8b87-5b00-9471-801e7ed7c63d', 'Tyre 205/55R16 (Michelin Energy)', 'tyre-205-55r16-michelin', 'WHL-00703', 9800, 32, 'Michelin Energy XM2+ tyre in 205/55R16 — the standard sedan size in Bangladesh. Low rolling resistance saves fuel; silica compound grips wet roads during monsoon. Speed rating H (210 km/h). Treadwear warranty 60,000 km. Price per tyre — order qty 2 or 4 for sets. Free balancing at AutoHub service centres with purchase.', 'মিশেলিন এনার্জি টায়ার ২০৫/৫৫R১৬ — বর্ষায় ভালো গ্রিপ।', ARRAY['Toyota', 'Hyundai']::text[], ARRAY['Allion', 'Premio', 'Elantra', 'Axio']::text[], 2016, 2024, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
