INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('c5d82081-49a6-583b-8601-97eab878338e', '5f060a6d-8b87-5b00-9471-801e7ed7c63d', 'Tyre 225/60R17 (All-Terrain SUV)', 'tyre-225-60r17-all-terrain', 'WHL-00704', 12500, 24, 'All-terrain SUV tyre 225/60R17 with aggressive sidewall and open tread pattern. Handles tarmac, gravel, and light mud on Bangladesh rural roads. Reinforced sidewall resists punctures from road debris. M+S rated for monsoon grip. Per tyre pricing. Rotate every 10,000 km for even wear. Recommended pressure: 33 PSI front, 32 PSI rear (verify door sticker).', 'অল-টেরেইন SUV টায়ার ২২৫/৬০R১৭ — গ্রামীণ রাস্তায় উপযুক্ত।', ARRAY['Toyota', 'Nissan']::text[], ARRAY['Corolla Cross', 'X-Trail', 'Fortuner', 'Kicks']::text[], 2018, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
