INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('562bf2ba-8b18-56a4-98bd-1525237b9269', '5f060a6d-8b87-5b00-9471-801e7ed7c63d', 'Titanium Wheel Nut Set (20pc)', 'titanium-wheel-nut-set-20', 'WHL-00705', 4500, 28, 'Set of 20 open-end lug nuts with 12×1.5mm thread (standard Japanese/Korean). PVD titanium coating resists rust and cross-threading. Includes thin-wall socket for alloy wheels. Torque to 100 Nm with calibrated wrench. Lighter than steel nuts — marginal unsprung weight reduction. Theft-resistant design requires included key.', 'টাইটানিয়াম হুইল নাট সেট (২০টি) — মরিচা প্রতিরোধী।', ARRAY['Toyota', 'Hyundai', 'Nissan']::text[], ARRAY['Corolla Cross', 'Tucson', 'X-Trail', 'Creta']::text[], 2018, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
