INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('4d83f0f1-56e7-5be5-9b7b-89e2a61d41f9', '5f060a6d-8b87-5b00-9471-801e7ed7c63d', 'TPMS Sensor Valve (433MHz, 4pc)', 'tpms-sensor-valve-433mhz-4', 'WHL-00706', 8200, 16, 'Set of four 433MHz TPMS (tyre pressure monitoring) sensors. Pre-programmed for common Hyundai and Nissan platforms — professional relearn procedure required after installation. Replace when battery dies (typically 5–7 years) or when swapping alloy wheels. Includes rubber valve stems and nickel-plated caps. Essential for dashboard warning light reset after tyre service.', 'TPMS সেন্সর ভালভ ৪৩৩MHz (৪টি) — টায়ার প্রেসার মনিটরিং।', ARRAY['Hyundai', 'Nissan']::text[], ARRAY['Tucson', 'Santa Fe', 'X-Trail', 'Navara']::text[], 2019, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
