INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('9d67ea4f-0c4e-5423-abea-ed0afded2ed4', '0d86925f-b51b-5f03-9a49-4f9ce1560c42', 'Engine Oil 0W-20 Full Synthetic 4L', 'engine-oil-0w20-synthetic-4l', 'LUB-00802', 4800, 65, 'Ultra-low viscosity 0W-20 synthetic oil for latest-generation fuel-efficient engines. Reduces internal friction for improved fuel economy (up to 2% vs 5W-30). Factory fill specification for many hybrid and Atkinson-cycle engines. 4-litre bottle. Do not use in older high-mileage engines with worn rings — consult service advisor.', '০W-20 ফুল সিনথেটিক অয়েল — জ্বালানি সাশ্রয়ী আধুনিক ইঞ্জিনের জন্য।', ARRAY['Toyota', 'Hyundai']::text[], ARRAY['Allion', 'Premio', 'Corolla Cross', 'Creta']::text[], 2019, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
