INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('7e0178e0-0282-5447-b871-84c83fe41460', '0d86925f-b51b-5f03-9a49-4f9ce1560c42', 'ATF Automatic Transmission Fluid 4L', 'atf-transmission-fluid-4l', 'LUB-00803', 3600, 45, 'Premium ATF Type-IV / SP-IV equivalent automatic transmission fluid. Ensures smooth shift quality and protects clutch packs from wear. 4-litre pack for partial fluid exchange; full drain requires 8–10 litres depending on model. Change every 40,000–60,000 km. Use correct specification — wrong fluid causes shift shudder and premature failure.', 'ATF অটোমেটিক ট্রান্সমিশন ফ্লুইড ৪L — মসৃণ গিয়ার শিফট।', ARRAY['Toyota', 'Hyundai', 'Nissan']::text[], ARRAY['Corolla Cross', 'Tucson', 'X-Trail', 'Sonata']::text[], 2017, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
