INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('093c2f17-8fb6-59f3-8120-c0469aa5bfbb', '0d86925f-b51b-5f03-9a49-4f9ce1560c42', 'Coolant Concentrate 1L (Pink OAT)', 'coolant-concentrate-1l-pink', 'LUB-00804', 850, 100, 'Organic Acid Technology (OAT) long-life coolant concentrate in pink/red colour. Mix 50:50 with distilled water for −35°C freeze protection. Service interval: 5 years or 100,000 km. Compatible with aluminium radiators and modern engine metals. Never mix with green IAT coolant. 1-litre bottle makes 2 litres ready-to-use coolant.', 'পিঙ্ক OAT কুল্যান্ট কনসেন্ট্রেট ১L — দীর্ঘস্থায়ী রক্ষণাবেক্ষণ।', ARRAY['Toyota', 'Hyundai', 'Nissan']::text[], ARRAY['Allion', 'Axio', 'i10', 'Sunny', 'Magnite']::text[], 2016, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
