INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('f8bca97d-8b55-52be-901d-d4a8d98ffc96', '0d86925f-b51b-5f03-9a49-4f9ce1560c42', 'Brake Fluid DOT 4 Plus 500ml', 'brake-fluid-dot4-plus-500ml', 'LUB-00805', 450, 85, 'High-performance DOT 4+ brake fluid in handy 500 ml bottle for top-up or single-wheel bleed. Exceeds ISO 4925 Class 4 specification. Low moisture absorption formula for extended service life. Essential during brake pad and caliper service. Store in cool, dry place; use within 12 months of opening.', 'ব্রেক ফ্লুইড DOT 4+ ৫০০ml — ব্রেক সার্ভিসের সময় প্রয়োজন।', ARRAY['Toyota', 'Hyundai', 'Nissan']::text[], ARRAY['Fortuner', 'Santa Fe', 'Navara', 'Corolla Cross']::text[], 2018, 2025, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
