INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('547dec76-8e57-5633-a149-4bfc8360d7b6', '6f72743e-d9a0-5c2d-a26d-f50a6b853fc7', 'Type 2 AC Charging Cable 7 kW (5m)', 'type2-ac-charging-cable-7kw', 'EV-00102', 12500, 45, 'Portable Type 2 to Type 2 charging cable rated for 7 kW single-phase AC charging (32A). IP55 weatherproof connectors for outdoor use in Bangladesh monsoon conditions. 5-metre length reaches most home parking setups. Built-in overcurrent and overheating protection. Essential accessory for overnight home charging when wall box is not yet installed.', 'টাইপ ২ AC চার্জিং কেবল ৭ kW — বাড়িতে রাতে চার্জের জন্য অপরিহার্য।', ARRAY['BAW', 'Toyota', 'Hyundai', 'Nissan']::text[], ARRAY['Pony', 'EC3', 'EU5', 'Corolla Cross']::text[], 2020, 2026, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
