INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('5ad75a85-1458-5727-81a7-b0171f57b516', '6f72743e-d9a0-5c2d-a26d-f50a6b853fc7', 'Onboard Charger 6.6 kW (BAW)', 'baw-onboard-charger-6kw', 'EV-00103', 42000, 12, 'OEM-spec onboard AC charger module for BAW EV models. Converts single-phase 220V household supply to DC for the battery pack at up to 6.6 kW. Plug-and-play replacement for failed units showing charging fault codes or intermittent AC charging. Includes mounting bracket and high-voltage warning labels. Installation by certified EV technician only.', 'BAW ইভি অনবোর্ড চার্জার ৬.৬ kW — AC চার্জিং সমস্যার রিপ্লেসমেন্ট।', ARRAY['BAW']::text[], ARRAY['Pony', 'EC3', 'EU5', 'EV6 Cargo']::text[], 2022, 2026, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
