INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('719b79cf-f881-5a5a-b661-bf80ce7e7a93', '6f72743e-d9a0-5c2d-a26d-f50a6b853fc7', 'Regenerative Brake Pad Set (EV)', 'regenerative-brake-pad-set-ev', 'EV-00105', 5800, 32, 'Low-dust ceramic brake pad set engineered for EVs with heavy regenerative braking use. Reduced copper formula meets environmental standards while maintaining strong friction for emergency stops when regen is insufficient. Includes wear sensor clips and anti-squeal shims. Front axle set — order rear set separately. Service interval: 30,000–40,000 km depending on driving style.', 'ইভি রিজেন ব্রেক প্যাড সেট — কম ধুলো, উচ্চ নিরাপত্তা।', ARRAY['BAW']::text[], ARRAY['Pony', 'EC3', 'EU5']::text[], 2022, 2026, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
