INSERT INTO parts (id, category_id, name, slug, part_number, price, stock, description, description_bn, compatible_brands, compatible_models, compatible_year_from, compatible_year_to, is_active, created_at) VALUES ('3025e4d4-72b1-56da-97ac-8b0971584984', '6f72743e-d9a0-5c2d-a26d-f50a6b853fc7', 'Cabin Heat Pump Assembly (EV)', 'cabin-heat-pump-assembly-ev', 'EV-00106', 35000, 10, 'Heat pump module for efficient cabin heating and cooling in BAW electric sedans and SUVs. Uses less battery energy than resistive heaters — extends winter range by up to 15%. Includes expansion valve and refrigerant lines pre-flushed with R1234yf. Professional AC machine evacuation and recharge required on installation.', 'ইভি ক্যাবিন হিট পাম্প — শীতে রেঞ্জ বাঁচাতে কম বিদ্যুৎ ব্যবহার।', ARRAY['BAW']::text[], ARRAY['EC3', 'EU5']::text[], 2023, 2026, TRUE, '2026-07-03T00:00:00.000Z'::timestamp) ON CONFLICT (slug) DO NOTHING;
