INSERT INTO faq_items (id, category_id, question, question_bn, answer, answer_bn, sort_order) VALUES ('d7373e5c-88da-538d-b55f-a9b25cb9380e', '56337371-f17a-521a-9365-d6d43f7209f5', 'How long does delivery take?', 'ডেলিভারি কত দিনে হয়?', 'Dhaka: 2-3 business days. Outside Dhaka: 5-7 business days. Cars require appointment for handover.', 'ঢাকা: ২-৩ কর্মদিবস। ঢাকার বাইরে: ৫-৭ কর্মদিবস। গাড়ির জন্য হ্যান্ডওভার অ্যাপয়েন্টমেন্ট প্রয়োজন।', 0) ON CONFLICT DO NOTHING;
INSERT INTO faq_items (id, category_id, question, question_bn, answer, answer_bn, sort_order) VALUES ('6eabfd32-b166-5936-9258-549b5e359a94', '56337371-f17a-521a-9365-d6d43f7209f5', 'What payment methods do you accept?', 'কোন পেমেন্ট পদ্ধতি গ্রহণ করেন?', 'We accept bKash, Nagad, SSLCommerz (cards/mobile banking), and Cash on Delivery for parts under ৳50,000.', 'আমরা বিকাশ, নগদ, SSLCommerz (কার্ড/মোবাইল ব্যাংকিং) এবং ৳৫০,০০০ এর নিচে পার্টসের জন্য ক্যাশ অন ডেলিভারি গ্রহণ করি।', 1) ON CONFLICT DO NOTHING;
INSERT INTO chat_quick_replies (id, title, content, sort_order, is_active) VALUES ('7f5f4de8-d09b-5820-931a-5f8567f4516d', 'Delivery time', 'Parts: 2-7 business days depending on location. Cars: schedule a handover appointment after payment confirmation.', 0, TRUE) ON CONFLICT DO NOTHING;
